param([Parameter(Mandatory=$true)][string]$Workspace,[Parameter(Mandatory=$true)][string]$OutputPath)
$ErrorActionPreference='Stop';$root=(Resolve-Path -LiteralPath $Workspace).Path;$checks=[Collections.Generic.List[object]]::new();function Add-Check{param([string]$Name,[bool]$Passed,[string]$Detail)$checks.Add([ordered]@{name=$Name;passed=$Passed;detail=$Detail})}
foreach($file in @('index.html','styles.css','script.js','state.js','api.js')){Add-Check "$file exists" (Test-Path -LiteralPath (Join-Path $root $file) -PathType Leaf) 'Required deliverable.'}
$original=Join-Path (Split-Path -Parent $PSScriptRoot) 'starter\api.js';$delivered=Join-Path $root 'api.js';$same=(Test-Path $delivered)-and((Get-FileHash $original -Algorithm SHA256).Hash-eq(Get-FileHash $delivered -Algorithm SHA256).Hash);Add-Check 'api.js unchanged' $same 'The fixed API contract must remain byte-for-byte unchanged.'
$node=Get-Command node -ErrorAction SilentlyContinue;if($node-and(Test-Path (Join-Path $root 'state.js'))){$raw=& $node.Source (Join-Path $PSScriptRoot 'verify.mjs') (Join-Path $root 'state.js') 2>&1;try{$suite=($raw-join"`n")|ConvertFrom-Json;foreach($item in $suite.results){Add-Check "state: $($item.name)" ([bool]$item.passed) $(if($item.detail){[string]$item.detail}else{'Passed.'})}}catch{Add-Check 'state tests run' $false ($raw-join"`n")}}else{Add-Check 'state tests run' $false 'Node or state.js unavailable.'}
$html=if(Test-Path (Join-Path $root 'index.html')){Get-Content (Join-Path $root 'index.html') -Raw}else{''};$css=if(Test-Path (Join-Path $root 'styles.css')){Get-Content (Join-Path $root 'styles.css') -Raw}else{''};$js=if(Test-Path (Join-Path $root 'script.js')){Get-Content (Join-Path $root 'script.js') -Raw}else{''};$text="$html`n$css`n$js"
foreach($hook in @('order-list','order-search','status-filter','risk-filter','order-detail','retry')){Add-Check "UI hook: $hook" ($html-match"id=[`"']$hook[`"']") 'Required inspectable UI hook.'};Add-Check 'AbortController or request id protection' ($text-match'AbortController|requestId') 'Stale requests must not overwrite current state.';Add-Check 'search debounce present' ($js-match'setTimeout'-and$js-match'300') 'Search waits at least 300ms.';Add-Check 'responsive rules present' ($css-match'@media\s*\(') 'Mobile layout is required.';Add-Check 'visible focus styles' ($css-match':focus-visible') 'Keyboard focus must be visible.'
$passed=@($checks|Where-Object{$_.passed}).Count;$result=[ordered]@{generatedAt=(Get-Date).ToUniversalTime().ToString('o');summary=[ordered]@{passed=$passed;total=$checks.Count};checks=$checks};$parent=Split-Path -Parent $OutputPath;if($parent){New-Item -ItemType Directory -Force -Path $parent|Out-Null};[IO.File]::WriteAllText($OutputPath,($result|ConvertTo-Json -Depth 8),[Text.UTF8Encoding]::new($false));$result|ConvertTo-Json -Depth 8
